const newsItems = $('Execute a SQL query').all().map((i) => i.json);
const subscribers = $input.all().map((i) => i.json);

if (!subscribers.length) {
  return [];
}

function parseSources(raw) {
  if (Array.isArray(raw)) {
    return raw.map((v) => String(v).trim()).filter(Boolean);
  }
  if (typeof raw === 'string' && raw.trim()) {
    try {
      const parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) {
        return parsed.map((v) => String(v).trim()).filter(Boolean);
      }
    } catch (e) {}
  }
  return [];
}

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function formatDate(date, timezone) {
  try {
    return new Intl.DateTimeFormat('zh-CN', {
      month: 'long',
      day: 'numeric',
      timeZone: timezone,
    }).format(new Date(date));
  } catch {
    return new Intl.DateTimeFormat('zh-CN', {
      month: 'long',
      day: 'numeric',
      timeZone: 'Asia/Shanghai',
    }).format(new Date(date));
  }
}

function formatTime(date, timezone) {
  try {
    return new Intl.DateTimeFormat('zh-CN', {
      hour: '2-digit',
      minute: '2-digit',
      hour12: false,
      timeZone: timezone,
    }).format(new Date(date));
  } catch {
    return '';
  }
}

function pickNewsForSubscriber(preferredSources) {
  const sourceSet = preferredSources.length ? new Set(preferredSources) : null;
  const filtered = sourceSet
    ? newsItems.filter((n) => sourceSet.has(n.source_type))
    : newsItems.slice();

  if (!filtered.length) {
    return [];
  }

  const grouped = new Map();
  for (const row of filtered) {
    const key = row.source_type || 'Other';
    if (!grouped.has(key)) grouped.set(key, []);
    grouped.get(key).push(row);
  }

  const sourceOrder = preferredSources.length
    ? preferredSources
    : Array.from(grouped.keys());

  const picked = [];
  for (const source of sourceOrder) {
    const rows = grouped.get(source) || [];
    if (!rows.length) continue;

    rows.sort((a, b) => {
      if (source === 'HackerNews') {
        const scoreDiff = (Number(b.points) || 0) - (Number(a.points) || 0);
        if (scoreDiff !== 0) return scoreDiff;
      }
      return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
    });

    const perSourceLimit = source === 'HackerNews' ? 5 : 4;
    picked.push(...rows.slice(0, perSourceLimit));
  }

  picked.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
  return picked.slice(0, 14);
}

function buildEmailBody(subscriber, pickedNews) {
  const timezone = subscriber.timezone || 'Asia/Shanghai';
  const displayName = (subscriber.name || '').trim() || 'Subscriber';
  const dateStr = formatDate(new Date(), timezone);

  let html = '';
  html += '<div style="font-family: Helvetica, Arial, sans-serif; max-width: 680px; margin: 0 auto; color: #202124;">';
  html += '<div style="padding-bottom: 14px; border-bottom: 2px solid #202124; margin-bottom: 20px;">';
  html += '<h1 style="margin: 0; font-size: 24px; font-weight: 700;">Tech Briefing</h1>';
  html += '<p style="margin: 6px 0 0; color: #5f6368; font-size: 13px;">' + escapeHtml(dateStr) + ' | ' + escapeHtml(timezone) + '</p>';
  html += '<p style="margin: 8px 0 0; color: #5f6368; font-size: 13px;">Hi, ' + escapeHtml(displayName) + '</p>';
  html += '</div>';

  if (!pickedNews.length) {
    html += '<div style="padding: 16px; border: 1px solid #dfe1e5; border-radius: 10px; background: #fafafa;">';
    html += '<p style="margin: 0; font-size: 14px; line-height: 1.7;">No items matched your selected sources in the last 24 hours.</p>';
    html += '</div>';
  } else {
    for (const news of pickedNews) {
      const sourceLabel = news.source_type || 'Other';
      const sentiment = (news.sentiment || 'Neutral').toString();
      const sentimentLabel = sentiment.charAt(0).toUpperCase() + sentiment.slice(1).toLowerCase();
      const sentimentColor = sentimentLabel === 'Positive' ? '#0d652d' : (sentimentLabel === 'Negative' ? '#a50e0e' : '#5f6368');
      const metricLabel = sourceLabel === 'HackerNews'
        ? ((Number(news.points) || 0) + ' Points')
        : formatTime(news.created_at, timezone);

      html += '<div style="margin-bottom: 20px;">';
      html += '<div style="font-size: 12px; color: #5f6368; margin-bottom: 5px;">';
      html += '<span style="font-weight: 600; color: #202124;">' + escapeHtml(sourceLabel) + '</span>';
      html += '<span style="margin: 0 8px;">&middot;</span>';
      html += '<span>' + escapeHtml(metricLabel) + '</span>';
      html += '<span style="margin: 0 8px;">&middot;</span>';
      html += '<span style="color: ' + sentimentColor + ';">' + escapeHtml(sentimentLabel) + '</span>';
      html += '</div>';

      html += '<h3 style="margin: 0 0 6px; font-size: 17px; line-height: 1.45;">';
      html += '<a href="' + escapeHtml(news.discussion_link || news.url || '#') + '" style="color: #1a73e8; text-decoration: none;">' + escapeHtml(news.title_cn || 'Untitled News') + '</a>';
      html += '</h3>';

      html += '<p style="margin: 0; font-size: 14px; color: #202124; line-height: 1.65;">' + escapeHtml(news.summary || 'No summary available') + '</p>';
      html += '</div>';
    }
  }

  html += '<div style="border-top: 1px solid #dfe1e5; margin-top: 28px; padding-top: 16px; text-align: center;">';
  html += '<a href="https://dashboard.trainingcqy.com" style="display: inline-block; background: #1a73e8; color: #fff; padding: 10px 18px; border-radius: 6px; text-decoration: none; font-size: 13px; font-weight: 600;">View Dashboard</a>';
  html += '<p style="margin: 14px 0 0; font-size: 12px; color: #70757a;">To unsubscribe, update your preference on the subscription page.</p>';
  html += '</div>';
  html += '</div>';

  return html;
}

const output = [];
for (const sub of subscribers) {
  if (!sub.email) continue;

  const preferredSources = parseSources(sub.source_preferences);
  const pickedNews = pickNewsForSubscriber(preferredSources);
  const timezone = sub.timezone || 'Asia/Shanghai';
  const subjectDate = formatDate(new Date(), timezone);

  output.push({
    json: {
      to_email: sub.email,
      subject: 'Tech Briefing | ' + subjectDate,
      email_body: buildEmailBody(sub, pickedNews),
    },
  });
}

return output;
